INSERT INTO `admin` (`id`, `username`, `password`) VALUES
(2, 'admin', 'stikom22j');
INSERT INTO `intents` (`tag`, `patterns`, `responses`) VALUES
(0, '[]', '[\"Berikut adalah langkah-langkah penawaran mata kuliah di STIKOM 22 Januari Kendari:\", \"1. Mahasiswa melakukan pembayaran uang SPP di BANK MANDIRI dengan nomor rekening 162 000 551 220 1 atas nama STIKOM 22 Januari Kendari.\", \"2. Mahasiswa membawa bukti pembayaran untuk divalidasi oleh Wakil Ketua II.\", \"3. Mahasiswa memperlihatkan bukti pembayaran yang telah divalidasi ke Wakil Ketua I untuk mengambil Kartu Rencana Studi (KRS), kemudian mengisi KRS.\", \"4. Mahasiswa memperlihatkan Kartu Hasil Studi (KHS) semester sebelumnya dan Kartu Bimbingan Akademik kepada dosen penasihat akademik untuk melakukan penawaran mata kuliah.\", \"5. Mahasiswa meminta tanda tangan Ketua Prodi untuk menyetujui mata kuliah yang akan diprogram pada semester ini.\", \"6. Mahasiswa meminta tanda tangan Wakil Ketua I untuk mengetahui mata kuliah yang diprogram pada semester ini.\", \"7. KRS yang telah ditandatangani oleh dosen PA, Ketua Prodi, dan Wakil Ketua I disimpan sebagai berikut:\", \"- KRS berwarna Kuning diserahkan ke BAAK.\", \"- KRS berwarna Pink diserahkan ke Ketua Prodi.\", \"- KRS berwarna Putih dipegang oleh mahasiswa.\", \"8. Setelah melakukan penawaran mata kuliah, mahasiswa menunggu jadwal perkuliahan dan mengikuti perkuliahan sesuai jadwal yang ditetapkan.\", \"Catatan: Bagi mahasiswa baru, Kartu Bimbingan Akademik dapat diambil di BAAK, dan tidak perlu memperlihatkan KHS semester sebelumnya.\"]'),
(1, '[\"Apa saja prospek kerja untuk lulusan Sistem Informasi?\", \"Bagaimana prospek kerja di bidang Sistem Informasi?\", \"Apa peluang kerja untuk lulusan Sistem Informasi?\", \"Apa saja pekerjaan yang bisa dilakukan oleh lulusan Sistem Informasi?\", \"Apa karir yang tersedia untuk lulusan Sistem Informasi?\", \"Apa saja pilihan karir untuk lulusan Sistem Informasi?\", \"Apa prospek karir di bidang Sistem Informasi?\", \"Apa pekerjaan yang cocok untuk lulusan Sistem Informasi?\", \"Apa saja peluang kerja di bidang Sistem Informasi?\", \"Apa jenis pekerjaan yang bisa dilakukan oleh lulusan Sistem Informasi?\", \"Lulusan SI bisa kerja di mana?\", \"Prospek kerja jurusan Sistem Informasi apa aja?\", \"Kalau lulus SI, kerja jadi apa?\", \"Apa aja sih peluang kerja buat lulusan SI?\", \"Kerja apa yang cocok buat lulusan Sistem Informasi?\", \"Jurusan SI punya prospek kerja bagus nggak?\", \"Apa aja sih pekerjaan buat lulusan SI?\", \"Lulusan Sistem Informasi biasanya kerja di bidang apa?\", \"Prospek karir lulusan SI gimana?\", \"Kerja apa yang bisa dilakukan setelah lulus SI?\"]', '[\"Prospek kerja untuk lulusan Sistem Informasi sangat beragam, di antaranya:\\n\\n- Analis dan Desainer Sistem Informasi\\n- Manager IT\\n- Programmer\\n- Database Administrator\\n- Web Developer\\n- Desainer Animasi dan Arsitektur Bangun Ruang 3D\\n- Desainer Komunikasi Visual dan Video Digital\\n- Advertising\\n- Praktisi E-commerce\\n- Online Startup\\n- Konsultan IT\\n- Peneliti dan Pengembang IT\\n- Dosen/Guru/Pendidik IT\\n- Pengusaha IT\"]'),
(2, '[\"Apa saja prospek kerja untuk lulusan Teknik Komputer?\", \"Bagaimana prospek kerja di bidang Teknik Komputer?\", \"Apa peluang kerja untuk lulusan Teknik Komputer?\", \"Apa saja pekerjaan yang bisa dilakukan oleh lulusan Teknik Komputer?\", \"Apa karir yang tersedia untuk lulusan Teknik Komputer?\", \"Apa saja pilihan karir untuk lulusan Teknik Komputer?\", \"Apa prospek karir di bidang Teknik Komputer?\", \"Apa pekerjaan yang cocok untuk lulusan Teknik Komputer?\", \"Apa saja peluang kerja di bidang Teknik Komputer?\", \"Apa jenis pekerjaan yang bisa dilakukan lulusan TK?\", \"Lulusan TK bisa kerja di mana?\", \"Prospek kerja jurusan Teknik Komputer apa saja?\", \"Kalau lulus TK, kerja jadi apa?\", \"Apa saja peluang kerja buat lulusan TK?\", \"Kerja apa yang cocok buat lulusan Teknik Komputer?\", \"Jurusan TK punya prospek kerja bagus nggak?\", \"Apa saja pekerjaan buat lulusan TK?\", \"Lulusan Teknik Komputer biasanya kerja di bidang apa?\", \"Setelah lulus TK, karirnya seperti apa?\"]', '[\"Prospek kerja untuk lulusan Teknik Komputer sangat beragam, di antaranya:\\n\\n- Perekayasa Perangkat Sistem Penunjang Komputer\\n- Perekayasa Sistem Komputer\\n- Arsitek dan Engineer Jaringan Komputer\\n- Perekayasa Robotik dan Otomatisasi\\n- Digital Sistem\\n- Teknisi Komputer\\n- Programmer\\n- Peneliti dan Pengembang IT\\n- Dosen/Guru/Pendidik IT\\n- Konsultan IT\\n- Pengusaha IT\"]'),
(3, '[\"Apa saja mata_kuliah di program studi Teknik Komputer?\", \"Bisa sebutkan mata_kuliah Teknik Komputer di STIKOM?\", \"Apa daftar mata_kuliah untuk Teknik Komputer?\", \"Apa saja mata_kuliah yang diajarkan di Teknik Komputer?\", \"Bisa berikan daftar mata_kuliah Teknik Komputer?\", \"Apa mata_kuliah yang ada di prodi Teknik Komputer?\", \"Apa saja mata_kuliah di jurusan Teknik Komputer?\", \"Bisa sebutkan daftar mata_kuliah Teknik Komputer?\", \"Apa mata_kuliah yang dipelajari di Teknik Komputer?\", \"Apa saja mata kuliah yang tersedia di Teknik Komputer?\", \"mata_kuliah apa aja yang ada di teknik komputer?\", \"Daftar matkul Teknik Komputer apa saja?\", \"Apa aja sih mata kuliah di jurusan teknik komputer?\", \"Kalau ambil TK, belajar apa aja?\", \"Mata kuliah TK di STIKOM apa aja?\", \"Apa saja matkul yang diajarkan di Teknik Komputer?\", \"Bisa kasih tahu daftar matkul teknik komputer?\", \"Apa aja sih yang dipelajari di Teknik Komputer?\", \"Mata kuliah apa yang ada di prodi teknik komputer?\", \"Daftar lengkap matkul teknik komputer apa?\", \"apasih matkul dari teknik komputer \"]', '[\"Berikut adalah daftar mata kuliah di program studi Teknik Komputer (TK):\\n\\n1. Pendidikan Agama (2 SKS)\\n2. Pendidikan Pancasila (2 SKS)\\n3. Bahasa Inggris (3 SKS)\\n4. Teknologi Informasi (2 SKS)\\n5. Logika Informatika (2 SKS)\\n6. Sistem Operasi (3 SKS)\\n7. Perangkat Lunak Aplikasi (3 SKS)\\n8. Elektronika Dasar (2 SKS)\\n9. Bahasa Indonesia (2 SKS)\\n10. Kewarganegaraan (2 SKS)\\n11. Sistem Basis Data (2 SKS)\\n12. Algoritma & Struktur Data (3 SKS)\\n13. Matematika Teknik (2 SKS)\\n14. Interaksi Manusia dan Komputer (2 SKS)\\n15. Teknik Mikroprosesor (2 SKS)\\n16. Fisika Komputasi (2 SKS)\\n17. Sistem Digital (2 SKS)\\n18. Sistem Mikrokontroler (2 SKS)\\n19. Rekayasa Perangkat Lunak (3 SKS)\\n20. Desain Basis Data (3 SKS)\\n21. Arsitektur Komputer (2 SKS)\\n22. Pemrograman Database 1 (3 SKS)\\n23. Komunikasi Data (2 SKS)\\n24. Desain & Instalasi Komputer (3 SKS)\\n25. Konsep Dasar Jaringan Komputer (2 SKS)\\n26. Sensor & Transducer (2 SKS)\\n27. Mekatronika (2 SKS)\\n28. Etika Profesi (2 SKS)\\n29. Pemrograman Database II (3 SKS)\\n30. Artificial Intelligence (3 SKS)\\n31. Desain WEB (2 SKS)\\n32. Troubleshooting Komputer (3 SKS)\\n33. Arsitektur Jaringan Komputer (2 SKS)\\n34. Pemrogrammable Logic Control (3 SKS)\\n35. Pemrosesan Paralel (2 SKS)\\n36. Pemrograman Database III (3 SKS)\\n37. Desain Sistem Pakar (3 SKS)\\n38. Aplikasi Mobile Program (3 SKS)\\n39. Teknik Instalasi Jaringan Komputer (3 SKS)\\n40. Teknik Telekomunikasi Seluler (2 SKS)\\n41. Perangkat Lunak Utilitas (2 SKS)\\n42. Desain Robotika I (2 SKS)\\n43. Sistem Embedded (2 SKS)\\n44. Metode Penelitian (2 SKS)\\n45. Computer Aided Design I (3 SKS)\\n46. Hukum Dan Undang-Undang ITE (2 SKS)\\n47. Testing & Implementasi SI (2 SKS)\\n48. Sistem Penunjang Keputusan (3 SKS)\\n49. Metode Riset Bisnis (2 SKS)\\n50. Desain Aplikasi Game (3 SKS)\\n51. Troubleshooting Jaringan Komputer (3 SKS)\\n52. Desain Robotika II (3 SKS)\\n53. Teknologi Nirkabel (2 SKS)\\n54. Pemrograman Berorientasi Objek (3 SKS)\\n55. Internet of Things (2 SKS)\\n56. Seminar (2 SKS)\\n57. Skripsi (6 SKS)\"]'),
(4, '[\"Apa saja mata_kuliah di program studi Sistem Informasi?\", \"Bisa sebutkan mata_kuliah Sistem Informasi di STIKOM?\", \"Apa daftar mata_kuliah untuk Sistem Informasi?\", \"Apa saja mata_kuliah yang diajarkan di Sistem Informasi?\", \"Bisa berikan daftar mata_kuliah Sistem Informasi?\", \"Apa mata_kuliah yang ada di prodi Sistem Informasi?\", \"Apa saja mata_kuliah di jurusan Sistem Informasi?\", \"Bisa sebutkan daftar mata_kuliah Sistem Informasi?\", \"Apa mata_kuliah yang dipelajari di Sistem Informasi?\", \"Apa saja mata kuliah yang tersedia di Sistem Informasi?\", \"Mata kuliah apa aja yang ada di SI?\", \"Daftar matkul Sistem Informasi apa saja?\", \"Apa aja sih mata kuliah di jurusan SI?\", \"Kalau ambil SI, belajar apa aja?\", \"Mata kuliah SI di STIKOM apa aja?\", \"Apa saja matkul yang diajarkan di Sistem Informasi?\", \"Bisa kasih tahu daftar matkul SI?\", \"Apa aja sih yang dipelajari di Sistem Informasi?\", \"Mata kuliah apa yang ada di prodi SI?\", \"Daftar lengkap matkul SI apa?\"]', '[\"Berikut adalah daftar mata kuliah di program studi Sistem Informasi (SI):\\n\\n1. Pendidikan Agama (2 SKS)\\n2. Pendidikan Pancasila (2 SKS)\\n3. Bahasa Inggris (3 SKS)\\n4. Teknologi Informasi (2 SKS)\\n5. Logika Informatika (2 SKS)\\n6. Sistem Operasi (3 SKS)\\n7. Perangkat Lunak Aplikasi (3 SKS)\\n8. Konsep Dasar Manajemen (2 SKS)\\n9. Teori Sistem Informasi (2 SKS)\\n10. Bahasa Indonesia (2 SKS)\\n11. Kewarganegaraan (2 SKS)\\n12. Sistem Basis Data (2 SKS)\\n13. Algoritma & Struktur Data (3 SKS)\\n14. Akuntansi (2 SKS)\\n15. Sistem Informasi Manajemen (2 SKS)\\n16. Konsep Dasar Multimedia (2 SKS)\\n17. Komputer Statistik (2 SKS)\\n18. Konsep Komunikasi Visual (2 SKS)\\n19. Rekayasa Perangkat Lunak (3 SKS)\\n20. Desain Basis Data (3 SKS)\\n21. Arsitektur Komputer (2 SKS)\\n22. Pemrograman Database 1 (3 SKS)\\n23. Komunikasi Data dan Jaringan Komputer (2 SKS)\\n24. Aplikasi Komputer Akuntansi (2 SKS)\\n25. Desain Komunikasi Visual (2 SKS)\\n26. Desain Multimedia (3 SKS)\\n27. Manajemen Sains (2 SKS)\\n28. Etika Profesi (2 SKS)\\n29. Pemrograman Database II (3 SKS)\\n30. Artificial Intelligence (2 SKS)\\n31. Desain WEB (2 SKS)\\n32. Analisis Sistem Informasi (3 SKS)\\n33. Sistem Informasi Perbankan (2 SKS)\\n34. Dasar Animasi (2 SKS)\\n35. Konsep Dasar Bisnis (2 SKS)\\n36. Broadcasting (3 SKS)\\n37. Pemrograman Database III (3 SKS)\\n38. Desain Sistem Pakar (3 SKS)\\n39. Aplikasi Mobile Program (3 SKS)\\n40. Desain Sistem Informasi (3 SKS)\\n41. Sistem Informasi Akuntansi (2 SKS)\\n42. Teknik Audio Video (2 SKS)\\n43. Animasi 2 Dimensi (2 SKS)\\n44. Pengolahan Citra Digital (3 SKS)\\n45. Metode Penelitian (2 SKS)\\n46. Computer Aided Design I (3 SKS)\\n47. Hukum Dan Undang-Undang ITE (2 SKS)\\n48. Testing & Implementasi SI (2 SKS)\\n49. Sistem Penunjang Keputusan (3 SKS)\\n50. Metode Riset Bisnis (2 SKS)\\n51. Desain Aplikasi Game (3 SKS)\\n52. Inovasi Kewirausahaan IT (2 SKS)\\n53. Computer Aided Design II (3 SKS)\\n54. Kuliah Kerja Nyata (4 SKS)\\n55. Manajemen Proyek SI (2 SKS)\\n56. Keamanan Sistem Informasi (2 SKS)\\n57. Sistem Informasi Geografis (2 SKS)\\n58. Sistem Informasi Pemasaran (2 SKS)\\n59. Seminar (2 SKS)\\n60. Skripsi (6 SKS)\"]'),
(5, '[\"Apa perbedaan antara Teknik Komputer dan Sistem Informasi?\", \"Bagaimana membedakan Teknik Komputer dan Sistem Informasi?\", \"Apa bedanya Teknik Komputer dengan Sistem Informasi?\", \"Apa perbedaan TK dan SI?\", \"Bagaimana perbedaan antara TK dan SI?\", \"Apa perbedaan jurusan Teknik Komputer dan Sistem Informasi?\", \"Apa beda Teknik Komputer dan Sistem Informasi?\", \"Apa perbedaan prodi TK dan SI?\", \"Bagaimana membedakan TK dan SI?\", \"Apa perbedaan antara Teknik Komputer (TK) dan Sistem Informasi (SI)?\", \"TK sama SI bedanya apa?\", \"Jurusan TK dan SI itu beda ya?\", \"Apa aja sih perbedaan TK sama SI?\", \"Kalau mau ambil TK atau SI, bedanya apa?\", \"TK itu lebih ke hardware ya?\", \"SI lebih ke software atau hardware?\", \"Apa beda fokus TK dan SI?\", \"TK sama SI, mana yang lebih cocok buat saya?\", \"Apa perbedaan utama TK dan SI?\", \"Jurusan TK dan SI itu mirip atau beda?\"]', '[\"Perbedaan antara Teknik Komputer (TK) dan Sistem Informasi (SI) adalah:\\n\\n**Teknik Komputer (TK):**\\n- Fokus pada perancangan dan pengembangan perangkat keras (hardware) dan sistem komputer.\\n- Mata kuliahnya lebih banyak terkait elektronika, mikrokontroler, robotika, dan jaringan komputer.\\n- Contoh mata kuliah: Elektronika Dasar, Teknik Mikroprosesor, Desain Robotika, Internet of Things.\\n\\n**Sistem Informasi (SI):**\\n- Fokus pada pengembangan sistem informasi berbasis teknologi untuk mendukung bisnis dan manajemen.\\n- Mata kuliahnya lebih banyak terkait manajemen, analisis sistem, dan pengembangan perangkat lunak.\\n- Contoh mata kuliah: Sistem Informasi Manajemen, Analisis Sistem Informasi, Desain Sistem Informasi, E-commerce.\"]'),
(6, '[\"Siapa saja dosen di STIKOM 22 Januari Kendari?\", \"Apa nama-nama dosen di STIKOM?\", \"Bisa sebutkan nama dosen di STIKOM 22 Januari?\", \"Siapa dosen yang mengajar di STIKOM?\", \"Apa saja nama dosen di kampus STIKOM?\", \"Bisa berikan daftar dosen di STIKOM?\", \"Siapa saja pengajar di STIKOM 22 Januari Kendari?\", \"Apa nama dosen yang ada di STIKOM?\", \"Bisa sebutkan nama-nama dosen di STIKOM 22 Januari?\", \"Siapa saja dosen yang mengajar di STIKOM?\", \"Dosen STIKOM siapa aja?\", \"Siapa aja dosen di STIKOM 22 Januari?\", \"Bisa kasih tahu daftar dosen STIKOM?\", \"Apa aja sih nama dosen di STIKOM?\", \"Dosen yang ngajar di STIKOM siapa?\", \"Siapa aja pengajar di STIKOM?\", \"Dosen STIKOM ada siapa aja?\", \"Bisa sebutin nama dosen STIKOM?\", \"Siapa aja yang ngajar di STIKOM 22 Januari?\", \"Dosen di STIKOM siapa saja?\"]', '[\"Berikut adalah daftar dosen di STIKOM 22 Januari Kendari:\\n\\n1. IRFAN SEPRIA BARESI, S.Kom, M.M\\n2. ETIKA PURNAMASARI, S.T., M.A.P\\n3. TUKKOT HAMONANGAN IMMANUEL, S.E., M.M\\n4. NELISA, S.Kom., M.Kom\\n5. ISWURI HANDAYANI, S.Kom., M.Kom\\n6. RUDIN, S.Sos., M.Si\\n7. JASMAN, S.Kom., M.Sos\\n8. HAMRIN, S.Kom., M.A.P\\n9. SALFIN, S.Kom., M.Si\"]'),
(7, '[\"Apa saja fasilitas yang ada di kampus STIKOM?\", \"Bisa sebutkan fasilitas di STIKOM 22 Januari Kendari?\", \"Apa fasilitas yang tersedia di STIKOM?\", \"Apa saja fasilitas kampus STIKOM?\", \"Bisa berikan daftar fasilitas di STIKOM?\", \"Apa fasilitas yang ada di kampus STIKOM 22 Januari?\", \"Apa saja fasilitas yang disediakan oleh STIKOM?\", \"Bisa sebutkan fasilitas yang ada di STIKOM?\", \"Apa fasilitas yang dimiliki oleh STIKOM?\", \"Apa saja fasilitas yang bisa dinikmati di STIKOM?\", \"Fasilitas STIKOM apa aja?\", \"Apa aja sih fasilitas di STIKOM?\", \"STIKOM punya fasilitas apa?\", \"Fasilitas kampus STIKOM ada apa saja?\", \"Bisa kasih tahu fasilitas STIKOM?\", \"Apa aja yang ada di kampus STIKOM?\", \"Fasilitas di STIKOM 22 Januari apa?\", \"STIKOM punya fasilitas lengkap nggak?\", \"Apa aja fasilitas yang disediakan STIKOM?\", \"Fasilitas STIKOM lengkap nggak?\"]', '[\"Fasilitas yang tersedia di kampus STIKOM 22 Januari Kendari antara lain:\\n\\n1. Ruang Kuliah Yang Kondusif Dilengkapi AC dan Infocus\\n2. Lab Komputer + AC\\n3. Perpustakaan\"]'),
(8, '[\"Apa sejarah STIKOM 22 Januari Kendari?\", \"Bagaimana sejarah berdirinya STIKOM?\", \"Bisa ceritakan sejarah STIKOM 22 Januari?\", \"Apa latar belakang berdirinya STIKOM?\", \"Bagaimana awal mula STIKOM 22 Januari Kendari?\", \"Apa sejarah berdirinya STIKOM 22 Januari?\", \"Bisa jelaskan sejarah STIKOM?\", \"Apa asal-usul STIKOM 22 Januari Kendari?\", \"Bagaimana sejarah pendirian STIKOM?\", \"Apa cerita di balik berdirinya STIKOM 22 Januari?\", \"Sejarah STIKOM gimana?\", \"Bisa ceritain sejarah STIKOM?\", \"Apa aja sih sejarah STIKOM 22 Januari?\", \"STIKOM berdiri sejak kapan?\", \"Bagaimana awal berdirinya STIKOM?\", \"Apa latar belakang STIKOM 22 Januari?\", \"STIKOM didirikan oleh siapa?\", \"Bisa kasih tahu sejarah STIKOM?\", \"Apa aja yang perlu diketahui tentang sejarah STIKOM?\", \"STIKOM 22 Januari punya sejarah apa?\"]', '[\"Sejarah STIKOM 22 Januari Kendari:\\n\\nSTIKOM 22 Januari Kendari didirikan oleh Bapak Rudin, S.Sos., M.Si, Bapak Irfan Sepria Baresi, S.Kom., M.M, dan Bapak Winoto Setyo Budi, S.Si. pada tanggal 22 Januari. Yayasan 22 Januari Kendari dibentuk sebagai badan hukum pendirian STIKOM. Pada tahun 2018, STIKOM resmi mendapatkan izin operasional dari Kementerian Riset, Teknologi, dan Pendidikan Tinggi dengan SK Nomor 1212/KPT/I/2018. STIKOM 22 Januari Kendari memiliki dua program studi, yaitu Sistem Informasi dan Teknik Komputer.\"]'),
(9, '[\"Apa visi dan misi STIKOM 22 Januari Kendari?\", \"Bagaimana visi dan misi kampus STIKOM?\", \"Bisa sebutkan visi dan misi STIKOM?\", \"Apa tujuan STIKOM 22 Januari?\", \"Bagaimana STIKOM mencapai visi dan misinya?\", \"Apa yang menjadi fokus STIKOM dalam pendidikan?\", \"Bagaimana STIKOM berkontribusi pada masyarakat?\", \"Apa nilai-nilai yang dianut oleh STIKOM?\", \"Bagaimana STIKOM mempersiapkan mahasiswa untuk masa depan?\", \"Apa keunggulan STIKOM dibanding kampus lain?\", \"Visi misi STIKOM apa?\", \"Apa aja sih visi misi STIKOM?\", \"STIKOM punya visi misi apa?\", \"Bisa kasih tahu visi misi STIKOM?\", \"Apa tujuan utama STIKOM?\", \"STIKOM fokus ke apa?\", \"Apa aja nilai-nilai STIKOM?\", \"STIKOM punya keunggulan apa?\", \"Bagaimana STIKOM membangun masa depan mahasiswa?\", \"Apa aja sih keunggulan STIKOM?\"]', '[\"Visi dan Misi STIKOM 22 Januari Kendari adalah menjadi sekolah tinggi ilmu komputer yang mandiri, kreatif, inovatif, dan kompetitif tingkat internasional 2040 di bidang Sistem Informasi dan Teknik Komputer.\"]'),
(10, '[\"Apa itu Teknik Komputer?\", \"Apa definisi Teknik Komputer?\", \"Bisa jelaskan pengertian Teknik Komputer?\", \"Apa yang dimaksud dengan Teknik Komputer?\", \"Apa arti dari Teknik Komputer?\", \"Bisa berikan penjelasan tentang Teknik Komputer?\", \"Apa pengertian dari Teknik Komputer?\", \"Apa itu jurusan Teknik Komputer?\", \"Bisa jelaskan apa itu Teknik Komputer?\", \"Apa makna Teknik Komputer?\", \"Teknik Komputer itu apa sih?\", \"Jurusan TK itu belajar apa?\", \"Apa fokus utama Teknik Komputer?\", \"Teknik Komputer itu lebih ke hardware atau software?\", \"Apa saja yang diajarkan di jurusan TK?\", \"Apa yang jadi dasar ilmu Teknik Komputer?\", \"Teknik Komputer itu mencakup apa saja?\", \"Apa bedanya Teknik Komputer dengan jurusan lain?\"]', '[\"Teknik Komputer adalah bidang ilmu yang mempelajari perancangan, pengembangan, dan implementasi sistem komputer, baik perangkat keras (hardware) maupun perangkat lunak (software). Jurusan ini menggabungkan ilmu komputer, elektronika, dan rekayasa untuk menciptakan sistem komputer yang efisien dan inovatif. Contoh aplikasinya meliputi pengembangan sistem embedded, robotika, jaringan komputer, dan Internet of Things (IoT).\"]'),
(11, '[\"Jam berapa dosen biasanya datang ke kampus?\", \"Bagaimana jadwal kedatangan dosen di STIKOM?\", \"Kapan dosen biasanya hadir di kampus?\", \"Apa jam kerja dosen di STIKOM?\", \"Bagaimana ketepatan waktu dosen datang ke kampus?\", \"Jam berapa dosen mulai mengajar di STIKOM?\", \"Kapan dosen tersedia untuk konsultasi di kampus?\", \"Bagaimana sistem kehadiran dosen di STIKOM?\", \"Apa jam kedatangan dosen di STIKOM 22 Januari?\", \"Kapan dosen biasanya berada di kampus?\", \"Dosen STIKOM jam berapa datang?\", \"Jam berapa dosen mulai ngajar?\", \"Kapan dosen ada di kampus?\", \"Dosen STIKOM jam berapa hadir?\", \"Apa aja sih jam kerja dosen?\", \"Dosen biasanya jam berapa datang?\", \"Jam berapa dosen STIKOM mulai kerja?\", \"Kapan dosen bisa ditemui di kampus?\", \"Dosen STIKOM jam berapa masuk?\", \"Jam kerja dosen STIKOM gimana?\"]', '[\"Informasi tentang jam kedatangan dosen dapat ditanyakan langsung ke bagian administrasi atau melalui dosen yang bersangkutan. Biasanya, dosen hadir sesuai jadwal mengajar mereka.\"]'),
(12, '[\"Bagaimana proses penawaran mata_kuliah di STIKOM?\", \"Apa langkah-langkah penawaran mata kuliah?\", \"Bagaimana cara menawar mata_kuliah?\", \"Apa syarat untuk menawar matakuliah?\", \"Bagaimana alur penawaran hingga skripsi?\", \"Apa yang harus dilakukan setelah penawaran mata_kuliah?\", \"Bagaimana cara memulai skripsi setelah penawaran?\", \"Apa hubungan antara penawaran mata_kuliah dan skripsi?\", \"Bagaimana proses akademik dari penawaran hingga skripsi?\", \"Apa tahapan skripsi di STIKOM?\", \"Cara mulai skripsi setelah penawaran gimana?\", \"Apa aja sih tahapan skripsi?\", \"Bagaimana alur penawaran sampai skripsi?\", \"Apa yang harus dilakukan setelah penawaran matkul?\", \"Proses skripsi di STIKOM gimana?\", \"Bagaimana cara mulai skripsi?\", \"Apa aja sih langkah-langkah skripsi?\", \"Bagaimana alur penawaran hingga skripsi?\", \"Apa aja sih tahapan skripsi di STIKOM?\", \"Bagaimana proses skripsi di STIKOM?\"]', '[\"Proses penawaran mata kuliah dimulai dengan pengisian KRS. Setelah itu, Anda bisa memulai skripsi setelah memenuhi syarat SKS dan IPK.\"]'),
(13, '[\"Bagaimana proses perbaikan nilai di STIKOM?\", \"Apa yang harus dilakukan jika mendapat nilai kurang?\", \"Bagaimana cara mengajukan perbaikan nilai?\", \"Bagaimana prosedur program ulang mata kuliah?\", \"Apa langkah-langkah perbaikan nilai di STIKOM?\", \"Bagaimana cara mengikuti SP di STIKOM?\", \"Apa syarat untuk mengikuti program ulang mata kuliah?\", \"Bagaimana alur perbaikan nilai dan SP di STIKOM?\", \"Apa yang harus dilakukan jika ingin memperbaiki nilai?\", \"Cara perbaikan nilai di STIKOM gimana?\", \"Apa aja sih langkah-langkah perbaikan nilai?\", \"Bagaimana cara ikut SP?\", \"Apa aja sih syarat program ulang?\", \"Bagaimana alur perbaikan nilai?\", \"Cara ikut SP di STIKOM gimana?\", \"Apa aja sih tahapan perbaikan nilai?\", \"Bagaimana proses program ulang matkul?\", \"Apa aja sih langkah-langkah SP?\", \"Bagaimana cara memperbaiki nilai di STIKOM?\"]', '[\"Proses perbaikan nilai, SP, dan program ulang di STIKOM dapat dilakukan dengan mengajukan permohonan ke bagian akademik dan memenuhi syarat yang ditetapkan.\"]'),
(14, '[\"Apa berita terbaru di kampus STIKOM?\", \"Bagaimana cara mengetahui berita kampus STIKOM?\", \"Apa informasi terbaru seputar STIKOM 22 Januari?\", \"Di mana bisa melihat berita resmi kampus STIKOM?\", \"Apa kegiatan terbaru di STIKOM 22 Januari?\", \"Bagaimana cara mengakses berita kampus STIKOM?\", \"Apa pengumuman terbaru dari kampus STIKOM?\", \"Di mana bisa mendapatkan informasi terbaru tentang STIKOM?\", \"Apa acara terbaru yang diadakan oleh STIKOM?\", \"Bagaimana cara mengetahui update berita kampus?\", \"Berita terbaru STIKOM apa?\", \"Apa aja sih berita terbaru di STIKOM?\", \"Di mana bisa lihat berita STIKOM?\", \"Apa aja sih kegiatan terbaru di STIKOM?\", \"Bagaimana cara cek berita kampus?\", \"Apa aja sih pengumuman terbaru STIKOM?\", \"Di mana bisa dapat info terbaru STIKOM?\", \"Apa aja sih acara terbaru di STIKOM?\", \"Bagaimana cara update berita kampus?\", \"Apa aja sih info terbaru STIKOM?\"]', '[\"Berita terbaru seputar kampus STIKOM dapat diakses melalui website resmi STIKOM 22 Januari Kendari: stikom22januarikendari.ac.id.\"]'),
(15, '[\"Apa alamat lengkap kampus STIKOM?\", \"Bagaimana akreditasi kampus STIKOM?\", \"Apa program studi yang tersedia di STIKOM?\", \"Apa saja fasilitas yang ada di kampus?\", \"Apa visi dan misi kampus STIKOM?\", \"Bagaimana sejarah berdirinya STIKOM?\", \"Apa saja kegiatan akademik di STIKOM?\", \"Bagaimana cara menghubungi administrasi kampus?\", \"Alamat STIKOM di mana?\", \"Apa aja sih prodi di STIKOM?\", \"Apa aja sih fasilitas STIKOM?\", \"Bagaimana sistem kuliah di STIKOM?\", \"Apa aja sih visi misi STIKOM?\", \"Sejarah STIKOM gimana?\", \"Apa aja sih kegiatan akademik STIKOM?\", \"Bagaimana cara hubungi admin STIKOM?\", \"Apa aja sih info umum STIKOM?\"]', '[\"Informasi umum tentang kampus STIKOM dapat ditemukan di website resmi: stikom22januarikendari.ac.id.\"]'),
(16, '[\"Bagaimana cara mendaftar sebagai mahasiswa baru di STIKOM?\", \"Apa syarat pendaftaran mahasiswa baru?\", \"Di mana saya bisa mendapatkan formulir pendaftaran?\", \"Berapa biaya pendaftaran mahasiswa baru?\", \"Apa dokumen yang diperlukan untuk pendaftaran?\", \"Bagaimana alur pendaftaran mahasiswa baru?\", \"Kapan pendaftaran mahasiswa baru dibuka?\", \"Apakah ada tes masuk untuk mahasiswa baru?\", \"Bagaimana cara mengisi formulir pendaftaran?\", \"Di mana saya bisa melihat pengumuman pendaftaran?\", \"Cara daftar mahasiswa baru di STIKOM gimana?\", \"Apa aja sih syarat pendaftaran?\", \"Di mana bisa ambil formulir pendaftaran?\", \"Berapa biaya daftar mahasiswa baru?\", \"Apa aja sih dokumen yang dibutuhkan?\", \"Bagaimana alur pendaftaran?\", \"Kapan pendaftaran dibuka?\", \"Ada tes masuk nggak?\", \"Bagaimana cara isi formulir pendaftaran?\", \"Di mana bisa lihat pengumuman pendaftaran?\"]', '[\"Pendaftaran mahasiswa baru di STIKOM dapat dilakukan secara online melalui website resmi kampus. Pastikan Anda memenuhi semua persyaratan yang ditetapkan.\"]'),
(17, '[\"Bagaimana jadwal perkuliahan di STIKOM?\", \"Apa kegiatan akademik yang ada di STIKOM?\", \"Bagaimana sistem perkuliahan di STIKOM?\", \"Apa saja kegiatan yang dilakukan selama perkuliahan?\", \"Bagaimana cara mengikuti kegiatan akademik di STIKOM?\", \"Apa yang harus dilakukan selama perkuliahan di STIKOM?\", \"Bagaimana cara mengetahui jadwal akademik di STIKOM?\", \"Apa kegiatan tambahan yang disediakan oleh STIKOM?\", \"Bagaimana sistem penilaian di STIKOM?\", \"Apa saja kegiatan non-akademik di STIKOM?\", \"Jadwal kuliah di STIKOM gimana?\", \"Apa aja sih kegiatan akademik STIKOM?\", \"Bagaimana sistem kuliah di STIKOM?\", \"Apa aja sih kegiatan selama kuliah?\", \"Bagaimana cara ikut kegiatan akademik?\", \"Apa yang harus dilakukan selama kuliah?\", \"Bagaimana cara cek jadwal akademik?\", \"Apa aja sih kegiatan tambahan STIKOM?\", \"Bagaimana sistem nilai di STIKOM?\", \"Apa aja sih kegiatan non-akademik STIKOM?\"]', '[\"Kegiatan perkuliahan dan akademik di STIKOM dapat dilihat melalui jadwal yang disediakan oleh bagian akademik atau website resmi kampus.\"]'),
(18, '[\"Bisa pinjam buku di perpustakaan STIKOM nggak?\", \"Apa saja yang bisa dipinjam di perpustakaan?\", \"Berapa banyak buku yang boleh dipinjam?\", \"Pinjam buku di STIKOM susah nggak?\", \"Apakah semua buku di perpustakaan bisa dipinjam?\", \"Buku apa yang tersedia untuk dipinjam?\", \"Mahasiswa baru bisa pinjam buku nggak?\", \"Pinjam buku di perpustakaan STIKOM bayar nggak?\", \"Ada batasan pinjam buku di STIKOM?\", \"Buku di perpustakaan STIKOM lengkap nggak?\", \"Pinjam buku itu perlu kartu apa?\", \"Bisa pinjam buku untuk semester ini?\", \"Perpustakaan STIKOM punya buku digital nggak?\", \"Pinjam buku di STIKOM lama nggak?\", \"Apa saja koleksi buku yang bisa dipinjam?\", \"Mahasiswa boleh pinjam berapa buku sekaligus?\", \"Pinjam buku di perpustakaan itu ribet nggak?\", \"Ada buku wajib yang bisa dipinjam?\", \"Perpustakaan STIKOM izinkan pinjam buku lama nggak?\", \"Pinjam buku di STIKOM harus ke mana?\"]', '[\"Untuk meminjam buku di perpustakaan STIKOM, Anda perlu mendaftar sebagai anggota perpustakaan terlebih dahulu. Setelah itu, Anda bisa meminjam buku dengan menunjukkan kartu anggota.\"]'),
(19, '[\"apa akreditasi STIKOM saat ini?\", \"bagaimana status akreditasi kampus STIKOM?\", \"apakah STIKOM sudah terakreditasi A?\", \"berapa nilai akreditasi program studi di STIKOM?\", \"kapan terakhir kali STIKOM melakukan akreditasi?\", \"STIKOM termasuk perguruan tinggi terakreditasi apa?\", \"apakah akreditasi STIKOM masih berlaku?\", \"dimana bisa cek akreditasi resmi STIKOM?\", \"akreditasi prodi di STIKOM seperti apa?\", \"berapa lama masa berlaku akreditasi STIKOM?\"]', '[\"akreditasi\"]'),
