INSERT INTO `intents` (`tag`, `patterns`, `responses`) VALUES
(66, '[\"Apa itu Sistem Informasi?\", \"Definisi Sistem Informasi apa sih?\", \"Sistem Informasi di STIKOM ngapain?\", \"Apa maksud dari jurusan SI?\", \"SI itu belajar apa aja?\", \"Apa yang dimaksud dengan Sistem Informasi?\", \"Sistem Informasi itu apa ya?\", \"Pengertian SI di kampus STIKOM?\", \"Apa arti Sistem Informasi dalam kuliah?\", \"SI di STIKOM fokusnya apa?\", \"Sistem Informasi ngurusin apa?\", \"Jurusan SI itu tentang apa sih?\", \"Apa bedanya SI sama IT?\", \"Sistem Informasi sama dengan Teknik Komputer nggak?\", \"Apa tujuan jurusan Sistem Informasi?\", \"SI itu lebih ke software atau bisnis?\", \"Apa dasar ilmu Sistem Informasi?\", \"Sistem Informasi mencakup apa aja?\", \"Apa yang dipelajari di SI STIKOM?\", \"Pengertian SI buat pemula apa?\", \"SI itu cuma ngoding nggak?\", \"Apa fungsi Sistem Informasi di perusahaan?\", \"Sistem Informasi itu ilmu apa?\", \"Jurusan SI STIKOM ngajarin apa?\", \"Apa sih inti dari Sistem Informasi?\", \"SI itu teknologi atau manajemen?\", \"Apa yang bikin SI penting?\", \"Sistem Informasi di dunia kerja ngapain?\"]', '[\"Sistem Informasi adalah bidang ilmu yang mempelajari bagaimana mengumpulkan, mengolah, menyimpan, dan mendistribusikan informasi menggunakan teknologi komputer. Di STIKOM, SI fokus pada pengembangan sistem untuk mendukung proses bisnis, seperti analisis data, desain database, dan aplikasi manajemen.\"]');
INSERT INTO `intents3` (`tag`, `patterns`, `responses`) VALUES
('akreditasi', '[\"apa akreditasi STIKOM saat ini?\", \"bagaimana status akreditasi kampus STIKOM?\", \"apakah STIKOM sudah terakreditasi A?\", \"berapa nilai akreditasi program studi di STIKOM?\", \"kapan terakhir kali STIKOM melakukan akreditasi?\", \"STIKOM termasuk perguruan tinggi terakreditasi apa?\", \"apakah akreditasi STIKOM masih berlaku?\", \"dimana bisa cek akreditasi resmi STIKOM?\", \"akreditasi prodi di STIKOM seperti apa?\", \"berapa lama masa berlaku akreditasi STIKOM?\"]', '[\"akreditasi stikom saat ini adalah\"]'),
('apa_itu_ipk', '[\"kenapa IPK penting bagi mahasiswa?\", \"IPK itu mengacu pada apa ya?\", \"apa hubungan IPK dengan kelulusan?\", \"bisakah kamu kasih penjelasan sederhana soal IPK?\", \"berapa nilai IPK minimal untuk lulus di STIKOM?\", \"apakah IPK mempengaruhi karir mahasiswa?\", \"bagaimana cara meningkatkan IPK di STIKOM?\", \"IPK itu dihitung berdasarkan apa?\", \"berapa IPK rata-rata mahasiswa STIKOM?\", \"apakah IPK mempengaruhi beasiswa di STIKOM?\"]', '[\"ipk adalah indeks prestasi kumulatif\"]'),
('apa_itu_khs', '[\"apa bedanya KHS dengan KRS?\", \"KHS itu mencatat apa saja?\", \"kenapa KHS penting untuk evaluasi akademik?\", \"apa fungsi utama KHS bagi mahasiswa?\", \"kapan KHS biasanya dikeluarkan di STIKOM?\", \"apakah KHS bisa dicetak secara online?\", \"siapa yang bertanggung jawab atas KHS mahasiswa?\", \"berapa nilai minimum yang harus ada di KHS?\", \"apakah KHS mempengaruhi kelulusan?\", \"bisakah kamu beri contoh format KHS di STIKOM?\"]', '[\"khs adalah\"]'),
('apa_itu_krs', '[\"kenapa KRS harus diisi setiap semester?\", \"KRS digunakan untuk apa oleh mahasiswa?\", \"apa tujuan pengisian KRS dalam perkuliahan?\", \"bagaimana cara kerja sistem KRS di perguruan tinggi?\", \"kapan batas waktu pengisian KRS di STIKOM?\", \"apakah KRS bisa diubah setelah diisi?\", \"siapa yang bertanggung jawab atas KRS mahasiswa?\", \"berapa mata kuliah maksimal dalam KRS?\", \"apakah ada denda jika telat isi KRS?\", \"bisakah kamu beri panduan pengisian KRS di STIKOM?\"]', '[\"krs adalah \"]'),
('beasiswa', '[\"bagaimana cara mengajukan beasiswa di stikom ?\", \"syarat mendapatkan beasiswa di STIKOM apa saja?\", \"bagaimana prosedur pengajuan beasiswa di STIKOM?\", \"kapan periode pendaftaran beasiswa dibuka di STIKOM?\", \"jenis beasiswa apa saja yang tersedia di STIKOM?\", \"apakah ada beasiswa untuk mahasiswa baru di STIKOM?\", \"berapa besar bantuan dari beasiswa di STIKOM?\", \"apakah ada beasiswa untuk mahasiswa berprestasi?\", \"bagaimana cara mempertahankan beasiswa di STIKOM?\", \"dimana bisa mendapatkan informasi lengkap tentang beasiswa STIKOM?\"]', '[\"beasiswa\"]'),
('berapa_biaya_kuliah', '[\"Berapa biaya kuliah STIKOM?\", \"berapa total biaya masuk STIKOM?\", \"biaya SPP per semester di STIKOM berapa?\", \"berapa estimasi biaya hidup selama kuliah di STIKOM?\", \"berapa uang pangkal untuk mahasiswa baru di STIKOM?\", \"apakah biaya kuliah di STIKOM terjangkau?\", \"berapa biaya tambahan selain SPP di STIKOM?\", \"apakah ada diskon biaya kuliah di STIKOM?\", \"berapa biaya untuk program studi tertentu di STIKOM?\", \"dimana bisa cek rincian biaya kuliah di STIKOM?\"]', '[\"biaya kuliah\"]'),
('berita_kampus', '[\"Apa berita terbaru di kampus STIKOM?\", \"Bagaimana cara mengetahui berita kampus STIKOM?\", \"Apa informasi terbaru seputar STIKOM 22 Januari?\", \"Di mana bisa melihat berita resmi kampus STIKOM?\", \"Apa kegiatan terbaru di STIKOM 22 Januari?\", \"Bagaimana cara mengakses berita kampus STIKOM?\", \"Apa pengumuman terbaru dari kampus STIKOM?\", \"Di mana bisa mendapatkan informasi terbaru tentang STIKOM?\", \"Apa acara terbaru yang diadakan oleh STIKOM?\", \"Bagaimana cara mengetahui update berita kampus?\", \"Berita terbaru STIKOM apa?\", \"Apa aja sih berita terbaru di STIKOM?\", \"Di mana bisa lihat berita STIKOM?\", \"Apa aja sih kegiatan terbaru di STIKOM?\", \"Bagaimana cara cek berita kampus?\", \"Apa aja sih pengumuman terbaru STIKOM?\", \"Di mana bisa dapat info terbaru STIKOM?\", \"Apa aja sih acara terbaru di STIKOM?\", \"Bagaimana cara update berita kampus?\", \"Apa aja sih info terbaru STIKOM?\"]', '[\"Berita terbaru seputar kampus STIKOM dapat diakses melalui website resmi STIKOM 22 Januari Kendari: stikom22januarikendari.ac.id.\"]'),
('biaya_yang_perlu_diperhatikan', '[\"apa saja biaya yang perlu diperhatikan ?\", \"selain SPP, apa saja biaya tambahan di STIKOM?\", \"ada biaya lain selain uang kuliah di STIKOM?\", \"apa saja pos-pos pengeluaran wajib mahasiswa STIKOM?\", \"biaya apa saja yang harus dipersiapkan sebelum kuliah di STIKOM?\", \"berapa biaya buku dan alat tulis di STIKOM?\", \"apakah ada biaya praktikum di STIKOM?\", \"berapa biaya wisuda di STIKOM?\", \"apakah ada biaya asrama atau kos di STIKOM?\", \"berapa biaya transportasi rata-rata untuk mahasiswa STIKOM?\"]', '[\"biaya yang perlu diperhatikan\"]'),
('daftar_dosen', '[\"Siapa saja dosen di STIKOM 22 Januari Kendari?\", \"Apa nama-nama dosen di STIKOM?\", \"Bisa sebutkan nama dosen di STIKOM 22 Januari?\", \"Siapa dosen yang mengajar di STIKOM?\", \"Apa saja nama dosen di kampus STIKOM?\", \"Bisa berikan daftar dosen di STIKOM?\", \"Siapa saja pengajar di STIKOM 22 Januari Kendari?\", \"Apa nama dosen yang ada di STIKOM?\", \"Bisa sebutkan nama-nama dosen di STIKOM 22 Januari?\", \"Siapa saja dosen yang mengajar di STIKOM?\", \"Dosen STIKOM siapa aja?\", \"Siapa aja dosen di STIKOM 22 Januari?\", \"Bisa kasih tahu daftar dosen STIKOM?\", \"Apa aja sih nama dosen di STIKOM?\", \"Dosen yang ngajar di STIKOM siapa?\", \"Siapa aja pengajar di STIKOM?\", \"Dosen STIKOM ada siapa aja?\", \"Bisa sebutin nama dosen STIKOM?\", \"Siapa aja yang ngajar di STIKOM 22 Januari?\", \"Dosen di STIKOM siapa saja?\"]', '[\"Berikut adalah daftar dosen di STIKOM 22 Januari Kendari:\\n\\n1. IRFAN SEPRIA BARESI, S.Kom, M.M\\n2. ETIKA PURNAMASARI, S.T., M.A.P\\n3. TUKKOT HAMONANGAN IMMANUEL, S.E., M.M\\n4. NELISA, S.Kom., M.Kom\\n5. ISWURI HANDAYANI, S.Kom., M.Kom\\n6. RUDIN, S.Sos., M.Si\\n7. JASMAN, S.Kom., M.Sos\\n8. HAMRIN, S.Kom., M.A.P\\n9. SALFIN, S.Kom., M.Si\"]'),
('informasi_kampus', '[\"Apa saja fasilitas yang ada di kampus STIKOM?\", \"Bisa sebutkan fasilitas di STIKOM 22 Januari Kendari?\", \"Apa fasilitas yang tersedia di STIKOM?\", \"Apa saja fasilitas kampus STIKOM?\", \"Bisa berikan daftar fasilitas di STIKOM?\", \"Apa fasilitas yang ada di kampus STIKOM 22 Januari?\", \"Apa saja fasilitas yang disediakan oleh STIKOM?\", \"Bisa sebutkan fasilitas yang ada di STIKOM?\", \"Apa fasilitas yang dimiliki oleh STIKOM?\", \"Apa saja fasilitas yang bisa dinikmati di STIKOM?\", \"Fasilitas STIKOM apa aja?\", \"Apa aja sih fasilitas di STIKOM?\", \"STIKOM punya fasilitas apa?\", \"Fasilitas kampus STIKOM ada apa saja?\", \"Bisa kasih tahu fasilitas STIKOM?\", \"Apa aja yang ada di kampus STIKOM?\", \"Fasilitas di STIKOM 22 Januari apa?\", \"STIKOM punya fasilitas lengkap nggak?\", \"Apa aja fasilitas yang disediakan STIKOM?\", \"Fasilitas STIKOM lengkap nggak?\"]', '[\"Fasilitas yang tersedia di kampus STIKOM 22 Januari Kendari antara lain:\\n\\n1. Ruang Kuliah Yang Kondusif Dilengkapi AC dan Infocus\\n2. Lab Komputer + AC\\n3. Perpustakaan\"]'),
('informasi_umum_kampus', '[\"Apa alamat lengkap kampus STIKOM?\", \"Apa program studi yang tersedia di STIKOM?\", \"Apa saja fasilitas yang ada di kampus?\", \"Bagaimana sistem perkuliahan di STIKOM?\", \"Apa visi dan misi kampus STIKOM?\", \"Bagaimana sejarah berdirinya STIKOM?\", \"Apa saja kegiatan akademik di STIKOM?\", \"Bagaimana cara menghubungi administrasi kampus?\", \"Alamat STIKOM di mana?\", \"Apa aja sih prodi di STIKOM?\", \"Apa aja sih fasilitas STIKOM?\", \"Bagaimana sistem kuliah di STIKOM?\", \"Apa aja sih visi misi STIKOM?\", \"Sejarah STIKOM gimana?\", \"Apa aja sih kegiatan akademik STIKOM?\", \"Bagaimana cara hubungi admin STIKOM?\", \"Apa aja sih info umum STIKOM?\"]', '[\"Informasi umum tentang kampus STIKOM dapat ditemukan di website resmi: stikom22januarikendari.ac.id.\"]'),
('jam_kedatangan_dosen', '[\"Jam berapa dosen biasanya datang ke kampus?\", \"Bagaimana jadwal kedatangan dosen di STIKOM?\", \"Kapan dosen biasanya hadir di kampus?\", \"Apa jam kerja dosen di STIKOM?\", \"Bagaimana ketepatan waktu dosen datang ke kampus?\", \"Jam berapa dosen mulai mengajar di STIKOM?\", \"Kapan dosen tersedia untuk konsultasi di kampus?\", \"Bagaimana sistem kehadiran dosen di STIKOM?\", \"Apa jam kedatangan dosen di STIKOM 22 Januari?\", \"Kapan dosen biasanya berada di kampus?\", \"Dosen STIKOM jam berapa datang?\", \"Jam berapa dosen mulai ngajar?\", \"Kapan dosen ada di kampus?\", \"Dosen STIKOM jam berapa hadir?\", \"Apa aja sih jam kerja dosen?\", \"Dosen biasanya jam berapa datang?\", \"Jam berapa dosen STIKOM mulai kerja?\", \"Kapan dosen bisa ditemui di kampus?\", \"Dosen STIKOM jam berapa masuk?\", \"Jam kerja dosen STIKOM gimana?\"]', '[\"Informasi tentang jam kedatangan dosen dapat ditanyakan langsung ke bagian administrasi atau melalui dosen yang bersangkutan. Biasanya, dosen hadir sesuai jadwal mengajar mereka.\"]'),
('kaprodi', '[\"siapa kaprodi prodi Sistem Informasi di STIKOM?\", \"kaprodi Teknik Informatika STIKOM siapa?\", \"siapa yang bertanggung jawab sebagai kaprodi di STIKOM?\", \"boleh tahu nama kaprodi di jurusan Komputer STIKOM?\", \"siapa kaprodi Manajemen Informatika di STIKOM?\", \"kaprodi Akuntansi STIKOM siapa ya?\", \"siapa pengelola program studi di STIKOM?\", \"kaprodi di STIKOM itu jabatan apa?\", \"siapa kaprodi paling senior di STIKOM?\", \"bisakah kamu beri info lengkap tentang kaprodi STIKOM?\"]', '[\"salfin S.kom, Msi untuk teknik komputer\", \"Etika Purnamasari, S.T., M.A.P\"]'),
('kegiatan_perkuliahan_dan_akademik', '[\"Bagaimana jadwal perkuliahan di STIKOM?\", \"Apa kegiatan akademik yang ada di STIKOM?\", \"Bagaimana sistem perkuliahan di STIKOM?\", \"Apa saja kegiatan yang dilakukan selama perkuliahan?\", \"Bagaimana cara mengikuti kegiatan akademik di STIKOM?\", \"Apa yang harus dilakukan selama perkuliahan di STIKOM?\", \"Bagaimana cara mengetahui jadwal akademik di STIKOM?\", \"Apa kegiatan tambahan yang disediakan oleh STIKOM?\", \"Bagaimana sistem penilaian di STIKOM?\", \"Apa saja kegiatan non-akademik di STIKOM?\", \"Jadwal kuliah di STIKOM gimana?\", \"Apa aja sih kegiatan akademik STIKOM?\", \"Bagaimana sistem kuliah di STIKOM?\", \"Apa aja sih kegiatan selama kuliah?\", \"Bagaimana cara ikut kegiatan akademik?\", \"Apa yang harus dilakukan selama kuliah?\", \"Bagaimana cara cek jadwal akademik?\", \"Apa aja sih kegiatan tambahan STIKOM?\", \"Bagaimana sistem nilai di STIKOM?\", \"Apa aja sih kegiatan non-akademik STIKOM?\"]', '[\"Kegiatan perkuliahan dan akademik di STIKOM dapat dilihat melalui jadwal yang disediakan oleh bagian akademik atau website resmi kampus.\"]'),
('kelas_ekstensi1', '[\"apakah ada kelas untuk karyawan?\", \"karyawan bisa kuliah di STIKOM tidak?\", \"apakah STIKOM menyediakan kelas untuk karyawan?\", \"bagaimana cara karyawan kuliah di STIKOM?\", \"adakah program kuliah malam untuk pekerja di STIKOM?\", \"apakah ada kelas fleksibel untuk profesional di STIKOM?\", \"bisakah pekerja paruh waktu mengikuti perkuliahan di STIKOM?\", \"apa syarat untuk mengikuti kelas karyawan di STIKOM?\", \"kapan jadwal kuliah untuk karyawan di STIKOM?\"]', '[\"kelas ekstensi1\"]'),
('kelas_ekstensi2', '[\"apakah mahasiswa yang tidak bekerja bisa mengambil kelas ekstensi?\", \"bisa ikut kelas ekstensi meski tidak bekerja?\", \"apakah kelas ekstensi hanya untuk karyawan?\", \"mahasiswa biasa boleh ikut kelas ekstensi?\", \"apa perbedaan kelas ekstensi dengan kelas reguler?\", \"siapa saja yang bisa mendaftar kelas ekstensi di STIKOM?\", \"apakah ada batasan usia untuk kelas ekstensi?\", \"bagaimana sistem pembelajaran di kelas ekstensi?\", \"apakah kelas ekstensi memiliki jadwal yang fleksibel?\", \"berapa lama durasi kuliah di kelas ekstensi STIKOM?\"]', '[\"kelas ekstensi\"]'),
('kode_etik_dosen', '[\"apa kode etik dosen STIKOM?\", \"bagaimana kode etik untuk dosen?\", \"kode etik dosen STIKOM apa saja?\", \"apa saja aturan kode etik dosen?\", \"kenapa kode etik dosen penting di STIKOM?\", \"apa sanksi jika dosen melanggar kode etiknya?\", \"siapa yang mengawasi pelaksanaan kode etik dosen?\", \"bagaimana proses penegakan kode etik dosen di STIKOM?\", \"dimana bisa membaca kode etik dosen STIKOM?\", \"apakah kode etik dosen berlaku untuk semua jenis pengajar?\"]', '[\"kode etik dosen\"]'),
('kode_etik_mahasiswa', '[\"apa kode etik mahasiswa?\", \"bagaimana kode etik untuk mahasiswa?\", \"kode etik mahasiswa STIKOM apa saja?\", \"apa saja aturan kode etik mahasiswa?\", \"kenapa kode etik mahasiswa penting?\", \"pelanggaran apa saja yang termasuk melanggar kode etik mahasiswa?\", \"bagaimana konsekuensi jika melanggar kode etik mahasiswa?\", \"apa poin utama dalam aturan perilaku mahasiswa?\", \"dimana bisa membaca kode etik mahasiswa STIKOM?\", \"siapa yang menegakkan kode etik mahasiswa di STIKOM?\"]', '[\"kode etik mahasiswa\"]'),
('langkah_penawaran_matkul', '[\"Apa langkah-langkah penawaran mata_kuliah di STIKOM?\", \"Bagaimana cara mendaftar mata_kuliah di STIKOM 22 Januari?\", \"Apa prosedur penawaran mata_kuliah di STIKOM?\", \"Bagaimana langkah-langkah pengisian KRS di STIKOM?\", \"Apa tahapan penawaran mata_kuliah di STIKOM?\", \"Bagaimana cara mengambil mata_kuliah di STIKOM?\", \"Bagaimana proses penawaran mata kuliah di STIKOM 22 Januari?\", \"Apa langkah-langkah pengambilan mata kuliah di STIKOM?\", \"Bagaimana cara mengisi KRS di STIKOM?\", \"Cara daftar matkul di STIKOM gimana?\", \"STIKOM punya prosedur apa untuk daftar mata kuliah?\", \"Langkah-langkah penawaran mata kuliah di STIKOM apa saja?\", \"Mau daftar mata kuliah di STIKOM, harus ngapain?\", \"Kalau mau daftar matkul semester depan, caranya gimana?\", \"Apa yang harus dilakukan setelah bayar SPP untuk daftar matkul?\", \"Daftar matkul STIKOM gimana?\", \"Cara daftar matkul?\", \"Gimana sih cara daftar matkul di STIKOM?\", \"Langkah2 penawaran matkul di STIKOM apa?\"]', '[\"Berikut adalah langkah-langkah penawaran mata kuliah di STIKOM 22 Januari Kendari:\\n\\n1. Mahasiswa melakukan pembayaran uang SPP di BANK MANDIRI dengan nomor rekening 162 000 551 220 1 atas nama STIKOM 22 Januari Kendari.\\n2. Mahasiswa membawa bukti pembayaran untuk divalidasi oleh Wakil Ketua II.\\n3. Mahasiswa memperlihatkan bukti pembayaran yang telah divalidasi ke Wakil Ketua I untuk mengambil Kartu Rencana Studi (KRS), kemudian mengisi KRS.\\n4. Mahasiswa memperlihatkan Kartu Hasil Studi (KHS) semester sebelumnya dan Kartu Bimbingan Akademik kepada dosen penasihat akademik untuk melakukan penawaran mata kuliah.\\n5. Mahasiswa meminta tanda tangan Ketua Prodi untuk menyetujui mata kuliah yang akan diprogram pada semester ini.\\n6. Mahasiswa meminta tanda tangan Wakil Ketua I untuk mengetahui mata kuliah yang diprogram pada semester ini.\\n7. KRS yang telah ditandatangani oleh dosen PA, Ketua Prodi, dan Wakil Ketua I disimpan sebagai berikut:\\n   - KRS berwarna Kuning diserahkan ke BAAK.\\n   - KRS berwarna Pink diserahkan ke Ketua Prodi.\\n   - KRS berwarna Putih dipegang oleh mahasiswa.\\n8. Setelah melakukan penawaran mata kuliah, mahasiswa menunggu jadwal perkuliahan dan mengikuti perkuliahan sesuai jadwal yang ditetapkan.\\n\\nCatatan: Bagi mahasiswa baru, Kartu Bimbingan Akademik dapat diambil di BAAK, dan tidak perlu memperlihatkan KHS semester sebelumnya.\"]'),
('latar_belakang_dosen', '[\"dari mana saja asal pendidikan dosen-dosen STIKOM?\", \"apakah dosen STIKOM bergelar doktor?\", \"bagaimana profil singkat para pengajar di STIKOM?\", \"berasal dari universitas mana para dosen STIKOM?\", \"apakah dosen STIKOM memiliki pengalaman internasional?\", \"siapa dosen paling senior di STIKOM?\", \"berapa persen dosen STIKOM yang bergelar profesor?\", \"apakah dosen STIKOM aktif dalam penelitian?\", \"dosen STIKOM memiliki sertifikasi apa saja?\", \"bisakah kamu beri info tentang latar belakang dosen STIKOM?\"]', '[\"latar_belakang_dosen\"]'),
('mata_kuliah', '[\"Apa saja mata kuliah di Sistem Informasi?\", \"Daftar mata kuliah\", \"Kurikulum Sistem Informasi\", \"Mata kuliah apa saja yang akan dipelajari?\", \"Apa saja mata kuliah wajib di program Sistem Informasi?\", \"Mata kuliah pilihan di Sistem Informasi\", \"Berapa banyak SKS yang harus diambil di Sistem Informasi?\", \"Apa saja mata kuliah yang diajarkan di semester pertama?\", \"Mata kuliah apa yang paling sulit diambil?\", \"Apa yang dipelajari di setiap semester di Sistem Informasi?\", \"Apa saja mata kuliah yang berhubungan dengan pengembangan perangkat lunak?\", \"Mata kuliah mana yang paling relevan dengan industri saat ini?\", \"Apa saja mata kuliah yang mendukung keterampilan analisis data?\", \"Bagaimana cara memilih mata kuliah di Sistem Informasi?\", \"Apa saja mata kuliah yang diajarkan di semester kedua?\", \"Mata kuliah apa yang paling menarik di Sistem Informasi?\", \"Apa saja mata kuliah yang berkaitan dengan manajemen proyek?\", \"Mata kuliah apa yang paling penting di Sistem Informasi?\", \"Apa saja mata kuliah yang diajarkan di semester akhir?\", \"Mata kuliah apa yang paling berguna untuk karir di bidang IT?\"]', '[\"Mata Kuliah wajib:\", \"1. Pendidikan Agama\", \"2. Pendidikan Pancasila\", \"3. Bahasa Inggris\", \"4. Teknologi Informasi\", \"5. Logika Informatika\", \"6. Sistem Operasi\", \"7. Perangkat Lunak Aplikasi\", \"8. Konsep Dasar Manajemen\", \"9. Teori Sistem Informasi\", \"Total beban studi: 146 SKS\", \"Kurikulum dirancang untuk memberikan pemahaman komprehensif tentang teknologi informasi, manajemen, dan pengembangan sistem.\"]'),
('mata_kuliah_sistem_informasi', '[\"Apa saja mata_kuliah di program studi Sistem Informasi?\", \"Bisa sebutkan mata_kuliah Sistem Informasi di STIKOM?\", \"Apa daftar mata_kuliah untuk Sistem Informasi?\", \"Apa saja mata_kuliah yang diajarkan di Sistem Informasi?\", \"Bisa berikan daftar mata_kuliah Sistem Informasi?\", \"Apa mata_kuliah yang ada di prodi Sistem Informasi?\", \"Apa saja mata_kuliah di jurusan Sistem Informasi?\", \"Bisa sebutkan daftar mata_kuliah Sistem Informasi?\", \"Apa mata_kuliah yang dipelajari di Sistem Informasi?\", \"Apa saja mata kuliah yang tersedia di Sistem Informasi?\", \"Mata kuliah apa aja yang ada di SI?\", \"Daftar matkul Sistem Informasi apa saja?\", \"Apa aja sih mata kuliah di jurusan SI?\", \"Kalau ambil SI, belajar apa aja?\", \"Mata kuliah SI di STIKOM apa aja?\", \"Apa saja matkul yang diajarkan di Sistem Informasi?\", \"Bisa kasih tahu daftar matkul SI?\", \"Apa aja sih yang dipelajari di Sistem Informasi?\", \"Mata kuliah apa yang ada di prodi SI?\", \"Daftar lengkap matkul SI apa?\"]', '[\"Berikut adalah daftar mata kuliah di program studi Sistem Informasi (SI):\\n\\n1. Pendidikan Agama (2 SKS)\\n2. Pendidikan Pancasila (2 SKS)\\n3. Bahasa Inggris (3 SKS)\\n4. Teknologi Informasi (2 SKS)\\n5. Logika Informatika (2 SKS)\\n6. Sistem Operasi (3 SKS)\\n7. Perangkat Lunak Aplikasi (3 SKS)\\n8. Konsep Dasar Manajemen (2 SKS)\\n9. Teori Sistem Informasi (2 SKS)\\n10. Bahasa Indonesia (2 SKS)\\n11. Kewarganegaraan (2 SKS)\\n12. Sistem Basis Data (2 SKS)\\n13. Algoritma & Struktur Data (3 SKS)\\n14. Akuntansi (2 SKS)\\n15. Sistem Informasi Manajemen (2 SKS)\\n16. Konsep Dasar Multimedia (2 SKS)\\n17. Komputer Statistik (2 SKS)\\n18. Konsep Komunikasi Visual (2 SKS)\\n19. Rekayasa Perangkat Lunak (3 SKS)\\n20. Desain Basis Data (3 SKS)\\n21. Arsitektur Komputer (2 SKS)\\n22. Pemrograman Database 1 (3 SKS)\\n23. Komunikasi Data dan Jaringan Komputer (2 SKS)\\n24. Aplikasi Komputer Akuntansi (2 SKS)\\n25. Desain Komunikasi Visual (2 SKS)\\n26. Desain Multimedia (3 SKS)\\n27. Manajemen Sains (2 SKS)\\n28. Etika Profesi (2 SKS)\\n29. Pemrograman Database II (3 SKS)\\n30. Artificial Intelligence (2 SKS)\\n31. Desain WEB (2 SKS)\\n32. Analisis Sistem Informasi (3 SKS)\\n33. Sistem Informasi Perbankan (2 SKS)\\n34. Dasar Animasi (2 SKS)\\n35. Konsep Dasar Bisnis (2 SKS)\\n36. Broadcasting (3 SKS)\\n37. Pemrograman Database III (3 SKS)\\n38. Desain Sistem Pakar (3 SKS)\\n39. Aplikasi Mobile Program (3 SKS)\\n40. Desain Sistem Informasi (3 SKS)\\n41. Sistem Informasi Akuntansi (2 SKS)\\n42. Teknik Audio Video (2 SKS)\\n43. Animasi 2 Dimensi (2 SKS)\\n44. Pengolahan Citra Digital (3 SKS)\\n45. Metode Penelitian (2 SKS)\\n46. Computer Aided Design I (3 SKS)\\n47. Hukum Dan Undang-Undang ITE (2 SKS)\\n48. Testing & Implementasi SI (2 SKS)\\n49. Sistem Penunjang Keputusan (3 SKS)\\n50. Metode Riset Bisnis (2 SKS)\\n51. Desain Aplikasi Game (3 SKS)\\n52. Inovasi Kewirausahaan IT (2 SKS)\\n53. Computer Aided Design II (3 SKS)\\n54. Kuliah Kerja Nyata (4 SKS)\\n55. Manajemen Proyek SI (2 SKS)\\n56. Keamanan Sistem Informasi (2 SKS)\\n57. Sistem Informasi Geografis (2 SKS)\\n58. Sistem Informasi Pemasaran (2 SKS)\\n59. Seminar (2 SKS)\\n60. Skripsi (6 SKS)\"]'),
('mata_kuliah_teknik_komputer', '[\"Apa saja mata_kuliah di program studi Teknik Komputer?\", \"Bisa sebutkan mata_kuliah Teknik Komputer di STIKOM?\", \"Apa daftar mata_kuliah untuk Teknik Komputer?\", \"Apa saja mata_kuliah yang diajarkan di Teknik Komputer?\", \"Bisa berikan daftar mata_kuliah Teknik Komputer?\", \"Apa mata_kuliah yang ada di prodi Teknik Komputer?\", \"Apa saja mata_kuliah di jurusan Teknik Komputer?\", \"Bisa sebutkan daftar mata_kuliah Teknik Komputer?\", \"Apa mata_kuliah yang dipelajari di Teknik Komputer?\", \"Apa saja mata_kuliah yang tersedia di Teknik Komputer?\", \"mata_kuliah apa aja yang ada di TK?\", \"Daftar matkul Teknik Komputer apa saja?\", \"Apa aja sih mata kuliah di jurusan TK?\", \"Kalau ambil TK, belajar apa aja?\", \"Mata kuliah TK di STIKOM apa aja?\", \"Apa saja matkul yang diajarkan di Teknik Komputer?\", \"Bisa kasih tahu daftar matkul TK?\", \"Apa aja sih yang dipelajari di Teknik Komputer?\", \"Mata kuliah apa yang ada di prodi TK?\", \"Daftar lengkap matkul TK apa?\"]', '[\"Berikut adalah daftar mata kuliah di program studi Teknik Komputer (TK):\\n\\n1. Pendidikan Agama (2 SKS)\\n2. Pendidikan Pancasila (2 SKS)\\n3. Bahasa Inggris (3 SKS)\\n4. Teknologi Informasi (2 SKS)\\n5. Logika Informatika (2 SKS)\\n6. Sistem Operasi (3 SKS)\\n7. Perangkat Lunak Aplikasi (3 SKS)\\n8. Elektronika Dasar (2 SKS)\\n9. Bahasa Indonesia (2 SKS)\\n10. Kewarganegaraan (2 SKS)\\n11. Sistem Basis Data (2 SKS)\\n12. Algoritma & Struktur Data (3 SKS)\\n13. Matematika Teknik (2 SKS)\\n14. Interaksi Manusia dan Komputer (2 SKS)\\n15. Teknik Mikroprosesor (2 SKS)\\n16. Fisika Komputasi (2 SKS)\\n17. Sistem Digital (2 SKS)\\n18. Sistem Mikrokontroler (2 SKS)\\n19. Rekayasa Perangkat Lunak (3 SKS)\\n20. Desain Basis Data (3 SKS)\\n21. Arsitektur Komputer (2 SKS)\\n22. Pemrograman Database 1 (3 SKS)\\n23. Komunikasi Data (2 SKS)\\n24. Desain & Instalasi Komputer (3 SKS)\\n25. Konsep Dasar Jaringan Komputer (2 SKS)\\n26. Sensor & Transducer (2 SKS)\\n27. Mekatronika (2 SKS)\\n28. Etika Profesi (2 SKS)\\n29. Pemrograman Database II (3 SKS)\\n30. Artificial Intelligence (3 SKS)\\n31. Desain WEB (2 SKS)\\n32. Troubleshooting Komputer (3 SKS)\\n33. Arsitektur Jaringan Komputer (2 SKS)\\n34. Pemrogrammable Logic Control (3 SKS)\\n35. Pemrosesan Paralel (2 SKS)\\n36. Pemrograman Database III (3 SKS)\\n37. Desain Sistem Pakar (3 SKS)\\n38. Aplikasi Mobile Program (3 SKS)\\n39. Teknik Instalasi Jaringan Komputer (3 SKS)\\n40. Teknik Telekomunikasi Seluler (2 SKS)\\n41. Perangkat Lunak Utilitas (2 SKS)\\n42. Desain Robotika I (2 SKS)\\n43. Sistem Embedded (2 SKS)\\n44. Metode Penelitian (2 SKS)\\n45. Computer Aided Design I (3 SKS)\\n46. Hukum Dan Undang-Undang ITE (2 SKS)\\n47. Testing & Implementasi SI (2 SKS)\\n48. Sistem Penunjang Keputusan (3 SKS)\\n49. Metode Riset Bisnis (2 SKS)\\n50. Desain Aplikasi Game (3 SKS)\\n51. Troubleshooting Jaringan Komputer (3 SKS)\\n52. Desain Robotika II (3 SKS)\\n53. Teknologi Nirkabel (2 SKS)\\n54. Pemrograman Berorientasi Objek (3 SKS)\\n55. Internet of Things (2 SKS)\\n56. Seminar (2 SKS)\\n57. Skripsi (6 SKS)\"]'),
('meminjam_buku', '[\"Bagaimana cara meminjam buku di perpustakaan?\", \"Apa prosedur meminjam buku di STIKOM?\", \"Berapa lama saya bisa meminjam buku?\", \"Bagaimana aturan peminjaman buku di perpustakaan?\", \"Apa syarat untuk meminjam buku?\", \"Bagaimana cara mengembalikan buku yang dipinjam?\", \"Apakah ada denda jika terlambat mengembalikan buku?\", \"Di mana saya bisa meminjam buku di kampus?\", \"Bagaimana sistem peminjaman buku di STIKOM?\", \"Apa fasilitas perpustakaan yang tersedia?\", \"Cara pinjam buku di perpustakaan gimana?\", \"Apa aja sih prosedur pinjam buku?\", \"Berapa lama bisa pinjam buku?\", \"Apa aja sih aturan pinjam buku?\", \"Apa syarat pinjam buku?\", \"Bagaimana cara kembalikan buku?\", \"Ada denda nggak kalau telat kembalikan buku?\", \"Di mana bisa pinjam buku?\", \"Bagaimana sistem pinjam buku di STIKOM?\", \"Apa aja sih fasilitas perpustakaan?\"]', '[\"Untuk meminjam buku di perpustakaan STIKOM, Anda perlu mendaftar sebagai anggota perpustakaan terlebih dahulu. Setelah itu, Anda bisa meminjam buku dengan menunjukkan kartu anggota.\"]'),
('organisasi_stikom', '[\"adakah unit kegiatan mahasiswa (UKM) di STIKOM?\", \"organisasi kemahasiswaan apa saja yang ada di STIKOM?\", \"apakah STIKOM memiliki komunitas atau organisasi kampus?\", \"bisakah kamu beri info tentang organisasi internal STIKOM?\", \"ada berapa organisasi mahasiswa di STIKOM?\", \"organisasi apa yang paling aktif di STIKOM?\", \"apakah ada organisasi olahraga di STIKOM?\", \"bagaimana cara bergabung dengan organisasi di STIKOM?\", \"organisasi seni di STIKOM ada nggak?\", \"siapa yang mengelola organisasi mahasiswa di STIKOM?\"]', '[\"organisasi_stikom\"]'),
('pendaftaran_mahasiswa_baru', '[\"Bagaimana cara mendaftar sebagai mahasiswa baru di STIKOM?\", \"Apa syarat pendaftaran mahasiswa baru?\", \"Di mana saya bisa mendapatkan formulir pendaftaran?\", \"Berapa biaya pendaftaran mahasiswa baru?\", \"Apa dokumen yang diperlukan untuk pendaftaran?\", \"Bagaimana alur pendaftaran mahasiswa baru?\", \"Kapan pendaftaran mahasiswa baru dibuka?\", \"Apakah ada tes masuk untuk mahasiswa baru?\", \"Bagaimana cara mengisi formulir pendaftaran?\", \"Di mana saya bisa melihat pengumuman pendaftaran?\", \"Cara daftar mahasiswa baru di STIKOM gimana?\", \"Apa aja sih syarat pendaftaran?\", \"Di mana bisa ambil formulir pendaftaran?\", \"Berapa biaya daftar mahasiswa baru?\", \"Apa aja sih dokumen yang dibutuhkan?\", \"Bagaimana alur pendaftaran?\", \"Kapan pendaftaran dibuka?\", \"Ada tes masuk nggak?\", \"Bagaimana cara isi formulir pendaftaran?\", \"Di mana bisa lihat pengumuman pendaftaran?\"]', '[\"Pendaftaran mahasiswa baru di STIKOM dapat dilakukan secara online melalui website resmi kampus. Pastikan Anda memenuhi semua persyaratan yang ditetapkan.\"]'),
('pengertian_teknik_komputer', '[\"Apa itu Teknik Komputer?\", \"Apa definisi Teknik Komputer?\", \"Bisa jelaskan pengertian Teknik Komputer?\", \"Apa yang dimaksud dengan Teknik Komputer?\", \"Apa arti dari Teknik Komputer?\", \"Bisa berikan penjelasan tentang Teknik Komputer?\", \"Apa pengertian dari Teknik Komputer?\", \"Apa itu jurusan Teknik Komputer?\", \"Bisa jelaskan apa itu Teknik Komputer?\", \"Apa makna Teknik Komputer?\", \"Teknik Komputer itu apa sih?\", \"Apa aja sih yang dipelajari di Teknik Komputer?\", \"Jurusan TK itu belajar apa?\", \"Apa bedanya TK sama jurusan lain?\", \"Teknik Komputer fokus ke apa?\", \"Apa aja sih yang diajarkan di TK?\", \"TK itu lebih ke hardware atau software?\", \"Apa aja sih yang dipelajari di jurusan TK?\", \"Teknik Komputer itu jurusan apa?\", \"Apa aja sih yang perlu diketahui tentang TK?\"]', '[\"Teknik Komputer adalah bidang ilmu yang mempelajari perancangan, pengembangan, dan implementasi sistem komputer, baik perangkat keras (hardware) maupun perangkat lunak (software). Jurusan ini menggabungkan ilmu komputer, elektronika, dan rekayasa untuk menciptakan sistem komputer yang efisien dan inovatif. Contoh aplikasinya meliputi pengembangan sistem embedded, robotika, jaringan komputer, dan Internet of Things (IoT).\"]'),
('perbedaan_tk_dan_si', '[\"Apa perbedaan antara Teknik Komputer dan Sistem Informasi?\", \"Bagaimana membedakan Teknik Komputer dan Sistem Informasi?\", \"Apa bedanya Teknik Komputer dengan Sistem Informasi?\", \"Apa perbedaan TK dan SI?\", \"Bagaimana perbedaan antara TK dan SI?\", \"Apa perbedaan jurusan Teknik Komputer dan Sistem Informasi?\", \"Apa beda Teknik Komputer dan Sistem Informasi?\", \"Apa perbedaan prodi TK dan SI?\", \"Bagaimana membedakan TK dan SI?\", \"Apa perbedaan antara Teknik Komputer (TK) dan Sistem Informasi (SI)?\", \"TK sama SI bedanya apa?\", \"Jurusan TK dan SI itu beda ya?\", \"Apa aja sih perbedaan TK sama SI?\", \"Kalau mau ambil TK atau SI, bedanya apa?\", \"TK itu lebih ke hardware ya?\", \"SI lebih ke software atau hardware?\", \"Apa beda fokus TK dan SI?\", \"TK sama SI, mana yang lebih cocok buat saya?\", \"Apa perbedaan utama TK dan SI?\", \"Jurusan TK dan SI itu mirip atau beda?\"]', '[\"Perbedaan antara Teknik Komputer (TK) dan Sistem Informasi (SI) adalah:\\n\\n**Teknik Komputer (TK):**\\n- Fokus pada perancangan dan pengembangan perangkat keras (hardware) dan sistem komputer.\\n- Mata kuliahnya lebih banyak terkait elektronika, mikrokontroler, robotika, dan jaringan komputer.\\n- Contoh mata kuliah: Elektronika Dasar, Teknik Mikroprosesor, Desain Robotika, Internet of Things.\\n\\n**Sistem Informasi (SI):**\\n- Fokus pada pengembangan sistem informasi berbasis teknologi untuk mendukung bisnis dan manajemen.\\n- Mata kuliahnya lebih banyak terkait manajemen, analisis sistem, dan pengembangan perangkat lunak.\\n- Contoh mata kuliah: Sistem Informasi Manajemen, Analisis Sistem Informasi, Desain Sistem Informasi, E-commerce.\"]'),
('pimpinan_stikom', '[\"siapa rektor STIKOM sekarang?\", \"nama pimpinan tertinggi di STIKOM siapa?\", \"siapa yang memimpin STIKOM tahun ini?\", \"bisakah kamu beri tahu nama dekan di STIKOM?\", \"siapa wakil rektor STIKOM saat ini?\"]', '[\"Pimpinan STIKOM saat ini adalah:\", \"- ketua yayasan: [rudin Sos., M.si]\", \"- pimpinan: [Irfan Sepria Baresi s.kom., M.M.]\"]'),
('prestasi_mahasiswa', '[\"apa saja pencapaian mahasiswa STIKOM?\", \"mahasiswa STIKOM pernah menang lomba apa saja?\", \"sebutkan beberapa prestasi membanggakan dari mahasiswa STIKOM.\", \"kapan terakhir kali mahasiswa STIKOM meraih juara nasional?\", \"apa prestasi internasional yang diraih mahasiswa STIKOM?\", \"apakah mahasiswa STIKOM sering ikut kompetisi?\", \"prestasi apa yang paling terkenal dari STIKOM?\", \"siapa mahasiswa STIKOM yang pernah juara umum?\", \"apakah ada mahasiswa STIKOM yang mendapat beasiswa prestasi?\", \"bisakah kamu beri daftar prestasi mahasiswa STIKOM?\"]', '[\"prestasi_mahasiswa\"]'),
('program_magang_yang_disediakan', '[\" apakah ada program magang yang disediakan oleh kampus ?\", \"apakah ada kerjasama magang antara STIKOM dan perusahaan?\", \"program magang di STIKOM seperti apa?\", \"kapan waktu pelaksanaan magang di STIKOM?\", \"apakah semua jurusan di STIKOM menyediakan program magang?\", \"berapa lama durasi program magang di STIKOM?\", \"apakah magang di STIKOM berbayar?\", \"bagaimana cara mendaftar program magang di STIKOM?\", \"siapa yang bertanggung jawab atas program magang di STIKOM?\", \"apakah ada sertifikat setelah menyelesaikan magang di STIKOM?\"]', '[\"program magang\"]'),
('prosedur_menawar_matkul', '[\"Bagaimana prosedur menawar mata_kuliah di STIKOM?\", \"Apa langkah-langkah penawaran mata kuliah?\", \"Bagaimana cara menawar mata_kuliah di STIKOM?\", \"Apa tahapan penawaran matakuliah di STIKOM?\", \"Bagaimana proses penawaran mata_kuliah di STIKOM?\", \"Apa yang harus dilakukan saat menawar mata_kuliah?\", \"Bagaimana alur penawaran mata_kuliah di STIKOM?\", \"Apa syarat untuk menawar mata_kuliah di STIKOM?\", \"Bagaimana cara mengisi KRS untuk penawaran mata_kuliah?\", \"Apa prosedur resmi penawaran mata_kuliah di STIKOM?\", \"Cara menawar matkul di STIKOM gimana?\", \"Apa aja sih langkah-langkah penawaran matkul?\", \"Bagaimana alur penawaran matkul?\", \"Apa yang harus dilakukan untuk menawar matkul?\", \"Prosedur penawaran matkul apa aja?\", \"Bagaimana cara daftar matkul di STIKOM?\", \"Apa aja sih syarat penawaran matkul?\", \"Bagaimana cara mengisi KRS untuk matkul?\", \"Apa aja sih tahapan penawaran matkul?\", \"Bagaimana proses penawaran matkul di STIKOM?\"]', '[\"Prosedur menawar mata kuliah di STIKOM meliputi:\\n1. Melakukan pembayaran SPP.\\n2. Mengisi KRS.\\n3. Menawarkan mata kuliah kepada dosen PA.\\n4. Mendapatkan persetujuan dari Ketua Prodi dan Wakil Ketua I.\\n5. Menyerahkan KRS yang telah ditandatangani ke BAAK.\"]'),
('proses_penawaran_perkuliahan_skripsi', '[\"Bagaimana proses penawaran mata_kuliah  di STIKOM?\", \"Apa langkah-langkah penawaran mata kuliah ?\", \"Bagaimana cara menawar mata_kuliah ?\", \"Apa syarat untuk menawar matakuliah ?\", \"Bagaimana alur penawaran hingga skripsi?\", \"Apa yang harus dilakukan setelah penawaran mata_kuliah ?\", \"Bagaimana cara memulai skripsi setelah penawaran?\", \"Apa hubungan antara penawaran mata_kuliah  dan skripsi?\", \"Bagaimana proses akademik dari penawaran hingga skripsi?\", \"Apa tahapan skripsi di STIKOM?\", \"Cara mulai skripsi setelah penawaran gimana?\", \"Apa aja sih tahapan skripsi?\", \"Bagaimana alur penawaran sampai skripsi?\", \"Apa yang harus dilakukan setelah penawaran matkul?\", \"Proses skripsi di STIKOM gimana?\", \"Bagaimana cara mulai skripsi?\", \"Apa aja sih langkah-langkah skripsi?\", \"Bagaimana alur penawaran hingga skripsi?\", \"Apa aja sih tahapan skripsi di STIKOM?\", \"Bagaimana proses skripsi di STIKOM?\"]', '[\"Proses penawaran mata kuliah dimulai dengan pengisian KRS. Setelah itu, Anda bisa memulai skripsi setelah memenuhi syarat SKS dan IPK.\"]'),
('proses_perbaikan_nilai_sp_program_ulang', '[\"Bagaimana proses perbaikan nilai di STIKOM?\", \"Apa yang harus dilakukan jika mendapat nilai kurang?\", \"Bagaimana cara mengajukan perbaikan nilai?\", \"Apa itu SP (Semester Pendek) di STIKOM?\", \"Bagaimana prosedur program ulang mata kuliah?\", \"Apa langkah-langkah perbaikan nilai di STIKOM?\", \"Bagaimana cara mengikuti SP di STIKOM?\", \"Apa syarat untuk mengikuti program ulang mata kuliah?\", \"Bagaimana alur perbaikan nilai dan SP di STIKOM?\", \"Apa yang harus dilakukan jika ingin memperbaiki nilai?\", \"Cara perbaikan nilai di STIKOM gimana?\", \"Apa aja sih langkah-langkah perbaikan nilai?\", \"Bagaimana cara ikut SP?\", \"Apa aja sih syarat program ulang?\", \"Bagaimana alur perbaikan nilai?\", \"Cara ikut SP di STIKOM gimana?\", \"Apa aja sih tahapan perbaikan nilai?\", \"Bagaimana proses program ulang matkul?\", \"Apa aja sih langkah-langkah SP?\", \"Bagaimana cara memperbaiki nilai di STIKOM?\"]', '[\"Proses perbaikan nilai, SP, dan program ulang di STIKOM dapat dilakukan dengan mengajukan permohonan ke bagian akademik dan memenuhi syarat yang ditetapkan.\"]'),
('prospek_kerja_sistem_informasi', '[\"Apa saja prospek kerja untuk lulusan Sistem Informasi?\", \"Bagaimana prospek kerja di bidang Sistem Informasi?\", \"Apa peluang kerja untuk lulusan Sistem Informasi?\", \"Apa saja pekerjaan yang bisa dilakukan oleh lulusan Sistem Informasi?\", \"Apa karir yang tersedia untuk lulusan Sistem Informasi?\", \"Apa saja pilihan karir untuk lulusan Sistem Informasi?\", \"Apa prospek karir di bidang Sistem Informasi?\", \"Apa pekerjaan yang cocok untuk lulusan Sistem Informasi?\", \"Apa saja peluang kerja di bidang Sistem Informasi?\", \"Apa jenis pekerjaan yang bisa dilakukan oleh lulusan Sistem Informasi?\", \"Lulusan SI bisa kerja di mana?\", \"Prospek kerja jurusan Sistem Informasi apa aja?\", \"Kalau lulus SI, kerja jadi apa?\", \"Apa aja sih peluang kerja buat lulusan SI?\", \"Kerja apa yang cocok buat lulusan Sistem Informasi?\", \"Jurusan SI punya prospek kerja bagus nggak?\", \"Apa aja sih pekerjaan buat lulusan SI?\", \"Lulusan Sistem Informasi biasanya kerja di bidang apa?\", \"Prospek karir lulusan SI gimana?\", \"Kerja apa yang bisa dilakukan setelah lulus SI?\"]', '[\"Prospek kerja untuk lulusan Sistem Informasi sangat beragam, di antaranya:\\n\\n- Analis dan Desainer Sistem Informasi\\n- Manager IT\\n- Programmer\\n- Database Administrator\\n- Web Developer\\n- Desainer Animasi dan Arsitektur Bangun Ruang 3D\\n- Desainer Komunikasi Visual dan Video Digital\\n- Advertising\\n- Praktisi E-commerce\\n- Online Startup\\n- Konsultan IT\\n- Peneliti dan Pengembang IT\\n- Dosen/Guru/Pendidik IT\\n- Pengusaha IT\"]'),
('prospek_kerja_teknik_komputer', '[\"Apa saja prospek kerja untuk lulusan Teknik Komputer?\", \"Bagaimana prospek kerja di bidang Teknik Komputer?\", \"Apa peluang kerja untuk lulusan Teknik Komputer?\", \"Apa saja pekerjaan yang bisa dilakukan oleh lulusan Teknik Komputer?\", \"Apa karir yang tersedia untuk lulusan Teknik Komputer?\", \"Apa saja pilihan karir untuk lulusan Teknik Komputer?\", \"Apa prospek karir di bidang Teknik Komputer?\", \"Apa pekerjaan yang cocok untuk lulusan Teknik Komputer?\", \"Apa saja peluang kerja di bidang Teknik Komputer?\", \"Apa jenis pekerjaan yang bisa dilakukan oleh lulusan Teknik Komputer?\", \"Lulusan TK bisa kerja di mana?\", \"Prospek kerja jurusan Teknik Komputer apa aja?\", \"Kalau lulus TK, kerja jadi apa?\", \"Apa aja sih peluang kerja buat lulusan TK?\", \"Kerja apa yang cocok buat lulusan Teknik Komputer?\", \"Jurusan TK punya prospek kerja bagus nggak?\", \"Apa aja sih pekerjaan buat lulusan TK?\", \"Lulusan Teknik Komputer biasanya kerja di bidang apa?\", \"Prospek karir lulusan TK gimana?\", \"Kerja apa yang bisa dilakukan setelah lulus TK?\"]', '[\"Prospek kerja untuk lulusan Teknik Komputer sangat beragam, di antaranya:\\n\\n- Perekayasa Perangkat Sistem Penunjang Komputer\\n- Perekayasa Sistem Komputer\\n- Arsitek dan Engineer Jaringan Komputer\\n- Perekayasa Robotik dan Otomatisasi\\n- Digital Sistem\\n- Teknisi Komputer\\n- Programmer\\n- Peneliti dan Pengembang IT\\n- Dosen/Guru/Pendidik IT\\n- Konsultan IT\\n- Pengusaha IT\"]'),
('sejarah_kampus', '[\"Apa sejarah STIKOM 22 Januari Kendari?\", \"Bagaimana sejarah berdirinya STIKOM?\", \"Bisa ceritakan sejarah STIKOM 22 Januari?\", \"Apa latar belakang berdirinya STIKOM?\", \"Bagaimana awal mula STIKOM 22 Januari Kendari?\", \"Apa sejarah berdirinya STIKOM 22 Januari?\", \"Bisa jelaskan sejarah STIKOM?\", \"Apa asal-usul STIKOM 22 Januari Kendari?\", \"Bagaimana sejarah pendirian STIKOM?\", \"Apa cerita di balik berdirinya STIKOM 22 Januari?\", \"Sejarah STIKOM gimana?\", \"Bisa ceritain sejarah STIKOM?\", \"Apa aja sih sejarah STIKOM 22 Januari?\", \"STIKOM berdiri sejak kapan?\", \"Bagaimana awal berdirinya STIKOM?\", \"Apa latar belakang STIKOM 22 Januari?\", \"STIKOM didirikan oleh siapa?\", \"Bisa kasih tahu sejarah STIKOM?\", \"Apa aja yang perlu diketahui tentang sejarah STIKOM?\", \"STIKOM 22 Januari punya sejarah apa?\"]', '[\"Sejarah STIKOM 22 Januari Kendari:\\n\\nSTIKOM 22 Januari Kendari didirikan oleh Bapak Rudin, S.Sos., M.Si, Bapak Irfan Sepria Baresi, S.Kom., M.M, dan Bapak Winoto Setyo Budi, S.Si. pada tanggal 22 Januari. Yayasan 22 Januari Kendari dibentuk sebagai badan hukum pendirian STIKOM. Pada tahun 2018, STIKOM resmi mendapatkan izin operasional dari Kementerian Riset, Teknologi, dan Pendidikan Tinggi dengan SK Nomor 1212/KPT/I/2018. STIKOM 22 Januari Kendari memiliki dua program studi, yaitu Sistem Informasi dan Teknik Komputer.\"]'),
('struktur_organisasi', '[\"tolong berikan gambaran struktur organisasi STIKOM.\", \"bagaimana susunan manajemen di STIKOM?\", \"apakah ada diagram struktur organisasi STIKOM?\", \"bisa jelaskan hirarki kepemimpinan di STIKOM?\", \"siapa saja yang termasuk dalam struktur organisasi STIKOM?\", \"bagaimana pembagian tugas di struktur organisasi STIKOM?\", \"dimana saya bisa melihat struktur organisasi STIKOM?\", \"apakah struktur organisasi STIKOM tersedia online?\", \"siapa yang menjabat di level manajemen STIKOM?\", \"bisakah kamu beri detail tentang divisi di STIKOM?\"]', '[\"struktur_organisasi sebagai berikut: ____\"]'),
('visi_misi_kampus', '[\"Apa visi dan misi STIKOM 22 Januari Kendari?\", \"Bagaimana visi dan misi kampus STIKOM?\", \"Bisa sebutkan visi dan misi STIKOM?\", \"Apa tujuan STIKOM 22 Januari?\", \"Bagaimana STIKOM mencapai visi dan misinya?\", \"Apa yang menjadi fokus STIKOM dalam pendidikan?\", \"Bagaimana STIKOM berkontribusi pada masyarakat?\", \"Apa nilai-nilai yang dianut oleh STIKOM?\", \"Bagaimana STIKOM mempersiapkan mahasiswa untuk masa depan?\", \"Apa keunggulan STIKOM dibanding kampus lain?\", \"Visi misi STIKOM apa?\", \"Apa aja sih visi misi STIKOM?\", \"STIKOM punya visi misi apa?\", \"Bisa kasih tahu visi misi STIKOM?\", \"Apa tujuan utama STIKOM?\", \"STIKOM fokus ke apa?\", \"Apa aja nilai-nilai STIKOM?\", \"STIKOM punya keunggulan apa?\", \"Bagaimana STIKOM membangun masa depan mahasiswa?\", \"Apa aja sih keunggulan STIKOM?\"]', '[\"Visi dan Misi STIKOM 22 Januari Kendari adalah menjadi sekolah tinggi ilmu komputer yang mandiri, kreatif, inovatif, dan kompetitif tingkat internasional 2040 di bidang Sistem Informasi dan Teknik Komputer.\"]');
